const fs = require('fs').promises;
const path = require('path');

const generateUniqueFilename = async (userId, basePath) => {
  let timestamp = Date.now();
  let filename = `CV_${userId}_${timestamp}.pdf`;
  let fullPath = path.join(basePath, filename);
  try {
    await fs.access(fullPath);
    // Le fichier existe, on réessaye avec un nouveau timestamp
    return generateUniqueFilename(userId, basePath);
  } catch {
    return filename;
  }
};
